INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02131', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一項屬於「生態系統觀點」在實務上的應用原則？①個案的問題和家庭的問題都是因為環境資源', '["干預的主軸在於中介、外部和鉅視系統，不重視微視層面，以 免將問題歸因於個人", "處遇的過程，工作者會強調個案的能力和力量", "生態系統觀點所定義的「標 的系統」（target system）是指案主面對的問題或需要改變的行為，不是案主或案主家庭本身", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02132', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一位獨居長者申請低收入戶身分，因為文件不齊全，後來補齊，卻遲遲沒有結果，對社工說：「我越來 越不相信你們，我已經盡力了，卻都沒有結果，你們是在刁難我，讓我申請不到…..」。社工回答如下：', '["你對申請的進度緩慢，感到失望和不滿，也開始懷疑是不是能夠申請到", "申請還沒有結果，你好像 覺得很挫折，你再等一等，一定沒有問題", "申請沒有結果讓你覺得生氣挫折，也開始懷疑社工和機構， 覺得沒希望  請將上述三個回應，依照同理的層次，從低層次到高層次，依序排列：", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02133', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '國中二年級的小強因為父親管教過度威權，經常挑戰其權威；現在正在和父親吵架，小強的姐姐即刻出 來試圖轉移父親的注意力，吵架的事就暫時平息，但是沒有解決父子吵架和家庭根本的問題。這種家庭 現象屬於下列何者？', '["三角關係", "均衡或平衡", "結盟", "角色衝突"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02134', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於家庭生態圖的描述何者錯誤？', '["是由家系圖擴大延伸出來", "重視家庭與內外在組織或者團體的關係", "可以用來檢視家庭問題的世代之間的關係", "透過圖形來表示性別和單位，線條來表示關係及其強弱"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02135', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對社會工作服務所提出的「人在情境中」，所要描述的是：', '["社會情境的處遇應該高於對於人的關懷", "介入環境提供服務是從事個案工作服務的捷徑", "強調人與環境互動下產生的交互影響", "造人、造物及造景應該一起進行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02136', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據Reamer的倫理指南，下列敘述何者錯誤？', '["生存權優於其他價值", "追求個人基本幸福時可以不用承擔後果", "在個人自由意志下的決定也要遵守法規", "公共利益優先於維護個人私益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02137', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者是與「非自願性案主」工作，最佳的晤談方式？', '["面質式會談，指出案主被強制的原因，藉以強化個案對問題的覺知", "動機式會談，社會工作者以討價還價的方式協商處遇目標", "和解式會談，社會工作者的立場是協助個案和強制其接受處遇的機構和解", "真誠式會談，社會工作者吐露自己也有過類似的艱困經驗，能了解案主感受"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02138', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '使用自我（use of self）是社會工作直接服務常用的技術，請問下列那一項屬於使用自我的做法？', '["深層次的同理心，將覺察到的個案情緒反應出來", "示範真誠的行為或適時揭露自己的經驗、想法", "透過案主的轉移，處理其和工作者的關係之議題", "同理心或設身處地和案主互動，並給予的正向回饋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02139', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者會針對個案問題進行評估（assessment）和診斷（diagnosis），下列有關兩者的敘述，何者正確？', '["診斷比較有焦點，診斷的結果可以作為評估的基礎", "診斷是簡要的描述案主問題，因為簡化和具體，比評估更有實務的用處", "評估是依據明確標準對個案問題進行簡要的描述，比較有用", "評估描述的是症狀，是診斷的基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02140', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作師在進行個案處遇時，與案主設定工作目標並且在一定的時間內完成，請問是屬於什麼工作模 式？', '["生態系統模式", "優勢觀點模式", "任務中心模式", "個案管理模式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
